var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"빌어먹을 바퀴벌레 같으니! 그만 좀 뒈져라!","JPN":"クソッタレのゴキブリめ！　いい加減くたばれ！","ENG":"That blasted Roach! Die already!","TWN":"妳這該死的蟑螂！算我求妳了，快下地獄吧！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"쏴! 쏴서 떨어뜨려!","JPN":"撃て！　 撃ち落としてしまえ！","ENG":"Fire! Shoot her down!","TWN":"射擊！把她射下來！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"쉽게 당할 것 같나! 당하는 쪽은 너희들이다!","JPN":"簡単にやられると思うか！　返り討ちにしてくれる！","ENG":"I won't go down so easily! You're the ones who's going down!","TWN":"你們以為我會這麼輕易就死掉嗎！該下地獄的是你們！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지원 따위 없어도 상관없어......!","JPN":"支援などなくとも構わん……！","ENG":"I don't need backup...","TWN":"就算沒有支援也無所謂……！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내가...... 나 혼자서라도 모두를 지키겠어!","JPN":"私が……私一人だけでも、皆を守ってみせる！","ENG":"I... I'll protect everyone all by myself!","TWN":"就算……就算只有我一個人，我也能保護大家！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>제 2, 제 3 포대가 파괴됐습니다!</color>","JPN":"<color=#ffd34c>第2、第3砲台が破壊されました！</color>","ENG":"<color=#ffd34c>The 2nd and 3rd batteries have been destroyed!</color>","TWN":"<color=#ffd34c>第2、第3炮臺被破壞了！</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>제 4, 제 5 포대도 전투 불능! 퇴각 명령을 내려 주십시오!</color>","JPN":"<color=#ffd34c>第4、第5砲台も戦闘不能！\\n退却命令を下してください！</color>","ENG":"<color=#ffd34c>The 4th and 5th batteries are also non-mission capable! Please give us the order to retreat!</color>","TWN":"<color=#ffd34c>第4、第5炮臺無法戰鬥！請下達撤退命令！</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"퇴각은 없다!","JPN":"退却などあり得ん！","ENG":"There will be no retreat!","TWN":"不准撤退！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"전원, 제 위치에서 전사할 때까지 싸워라!","JPN":"総員、持ち場にて砕け散るまで戦え！","ENG":"Hold your ground and fight until you die!","TWN":"全員堅守各自的位置，直到戰死為止！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"대체 왜 이렇게 무리하는 거야?","JPN":"どうしてこんな無茶をするの？","ENG":"Why are you pushing them so hard?","TWN":"到底為什麼要這麼拼命？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"꼭 정면승부를 고집할 필요는 없잖아?","JPN":"正面勝負に拘る必要はないはずよ。","ENG":"There's no reason to fight them head-on!","TWN":"根本沒有非得正面交鋒的必要啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"말했을 텐데? 사도께서 계시를 내리셨다고!","JPN":"言ったはずだが？　使徒が啓示を下されたのだ！","ENG":"I thought I made it clear. The Apostle has sent a revelation!","TWN":"我不是說過了嗎？使徒給我下達了啟示！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그게 무모한 전투를 계속하다가 전멸하란 명령은 아니겠지!","JPN":"まさか無謀な戦いを続けて全滅しろって命じられたとでもいうの！？","ENG":"Somehow I doubt that means we're supposed to get ourselves killed in a reckless battle!","TWN":"它應該沒有命令妳要有勇無謀地戰鬥，把自己搞到全滅吧！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"무모하다고? 내가 저 바퀴벌레에게 지기라도 할 거라는 뜻이냐?!","JPN":"無謀な戦いだと？　私があのゴキブリに負けるとでも言うのか！？","ENG":"Reckless? Are you saying that I'd lose to that Roach?","TWN":"有勇無謀？妳是說我會輸給那隻蟑螂？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그럼 아니야? 저 빌어먹을 것과 싸워 댄 게 벌써 몇 십 년째인데?","JPN":"そうなんじゃないの？　あの忌々しい奴ともう何十年も戦ってるんだから！","ENG":"Well, aren't you? We've been fighting that darned thing for decades now!","TWN":"難道不是嗎？妳和那個該死的傢伙已經打了幾十年了吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그 긴 시간 동안 녀석을 잡아먹지도 못하고, 의미 없는 소모전만 계속해 왔잖아!","JPN":"あれだけ長い間、奴を喰うどころか\\n無駄な消耗戦ばかり繰り返してきたじゃない！","ENG":"You never managed to devour her all that time! It was just a long, meaningless war of attrition!","TWN":"這麼長的時間，妳都沒能吞噬她，反而一直在進行毫無意義的消耗戰！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그런데 갑자기 어디서 무슨 자신감이 생겨난 건데?!","JPN":"なのにどうして急にそんな自信が湧いてきたの！？","ENG":"Where did you find this confidence all of a sudden?","TWN":"妳怎麼會突然這麼有自信？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"지금까지 승부를 내지 못한 건 네놈들이 무능했기 때문이다!","JPN":"今まで勝負がつかなかったのは貴様らが無能だったからだ！","ENG":"We've failed to defeat her all this time because you lot have been so incompetent!","TWN":"一直以來都沒有分出勝負，是因為你們太沒用了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"이번엔 내가 직접 나서서 그 바퀴벌레보다 더 우월하다는 걸 증명하겠어!","JPN":"今回は私自らが出向き、あのゴキブリより上であることを証明してやる！","ENG":"This time, I'll go out there myself and prove that I'm superior to that Roach!","TWN":"這次我會親自證明，我比那隻蟑螂更優秀！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"하지만......!","JPN":"でも……！","ENG":"But—","TWN":"但是……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"닥쳐! 이대로 목을 부러뜨려 버리기 전에!","JPN":"黙れ！　このまま首をへし折るぞ！","ENG":"Shut up! Before I snap your neck!","TWN":"閉嘴！在我扭斷妳脖子之前閉嘴！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_STING_BIG"},{"id":"L36_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"큭! 크으윽......!","JPN":"クッ！　クウウッ……！","ENG":"Ngh! Ngggh!","TWN":"唔！唔呃呃……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"내게는 시간이 부족해.","JPN":"私にはあまり時間がない。","ENG":"I need more time.","TWN":"我沒有時間了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"사도께서 강림하시고 나면 내 손으로 녀석을 처치할 기회는 사라진단 말이다.","JPN":"使徒が降臨なされば、私の手で奴を仕留める機会は永遠に失われるのだ。","ENG":"Once the Apostle arrives, I will no longer have the chance to take her out myself.","TWN":"使徒降臨後，我就沒機會親手殺掉那傢伙了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그러니...... 그러니 무슨 일이 있어도 그 전에 결판을 내야만 해!","JPN":"だから……たとえ何があろうと、その前に決着をつけねばならん！","ENG":"So... I must put an end to this before then, no matter what!","TWN":"所以……所以一定要在那之前分出勝負！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"알았...... 어...... 알았으니까......","JPN":"わがっ……だ……わがっだがら……","ENG":"Okay... Okay... I get it...","TWN":"知道……了……我知道了……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"제발...... 살려...... 줘......","JPN":"オネガイ……タス……ケテ……","ENG":"So please... Don't... kill me...","TWN":"求妳……放過……我……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"허억...... 허억......","JPN":"ぜぇ……ぜぇ……","ENG":"Huff... Huff...","TWN":"咳咳……咳咳……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"네 건방진 참견을 눈감아주는 건 이번이 마지막이다.","JPN":"お前の身の程知らずぶり​に目を瞑ってやるのも、今回で最後だ。","ENG":"This is the last time I will overlook your insolence.","TWN":"這是我最後一次，對妳的雞婆睜一隻眼閉一隻眼了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그러니 벌레 먹이가 되고 싶지 않다면 이번 교훈을 잊지 말도록.","JPN":"虫の餌になりたくなければ今回得た教訓を胸に刻め。","ENG":"Don't you ever forget this lesson if you wish to live.","TWN":"如果妳不想成為螻蟻的飼料，就不要忘記今天的教訓。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"아, 알겠어, 대장......","JPN":"わ、わかったわ、隊長ちゃん……","ENG":"O-okay, Commander...","TWN":"知、知道了，隊長……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"예고르, 들리나?","JPN":"イェゴール、聞こえるか？","ENG":"Can you hear me, Yegor?","TWN":"伊高爾，聽得見嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"네, 아주 잘 들립니다. 전대장님.","JPN":"はい、よく聞こえています。戦隊長。","ENG":"Loud and clear. Commander.","TWN":"是，聽得很清楚，隊長大人。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_TECH_09"},{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"바퀴벌레가 곧 너희 쪽으로 간다.","JPN":"ゴキブリはお前たちの方へ向かっている。","ENG":"The Roach is headed your way.","TWN":"蟑螂馬上會去你那邊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"내가 도착할 때까지 반드시 녀석의 발을 묶어 두도록.","JPN":"私が到着するまで奴を足止めしておけ。これは絶対命令だ。","ENG":"Keep her tied down until I get there.","TWN":"在我到達之前，你一定要拖住那個人的腳步。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"하, 하지만...... 또 건물 같은 걸 집어 던지면......","JPN":"で、ですが……またビルなんか投げ込まれた日には……","ENG":"B-but... What if she tosses a building at us again?","TWN":"但、但是……如果她又把大樓之類的東西扔過來……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"실패했다간 널 대원들에게 회식거리로 던져 주겠다.","JPN":"もし失敗したらお前たちを戦勝パーティーのつまみとして\\n他の隊員に振る舞ってやる。","ENG":"If you fail, I will have the troops feast on you.","TWN":"如果你失敗，我就會把你扔去當隊員們的晚餐。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"......아, 알겠습니다.","JPN":"……しょ、承知しました。","ENG":"Y-yes, ma'am.","TWN":"……是，知道了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"젠장...... 자기가 정말 전대장이라도 된다고 착각하는 건가?","JPN":"クソッ……本当に自分が戦隊長だと思い込んでやがるのか？","ENG":"Drat... Does she really think she's the actual commander or something?","TWN":"該死……他真的把自己當成戰隊隊長了？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"다들 멍하니 있지 말고 움직여! 오늘 여기서 바퀴벌레 놈과 끝장을 본다!","JPN":"ボケッとしてないで動け！\\n今日この場でゴキブリ野郎との決着をつける！","ENG":"Don't just stand there and get moving! We're going to deal with the Roach here, once and for all!","TWN":"大家別發呆了，快動起來！今天我們要和蟑螂決一死戰！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SHIELD_ADMIN_CORRUPT_MAZE","text":{"KOREA":"뭐야? 왜 그런 쓸데없는 짓을 해?","JPN":"何だ？　何だってそんな余計なことをしてるんだ？","ENG":"What? Why would we do something stupid like that?","TWN":"什麼？我們為什麼要做這種沒用的事情？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"SHIELD_ADMIN_CORRUPT_MAZE","text":{"KOREA":"이럴 시간에 방주로 가서 안에 있는 놈들이나 잡아먹을 것이지.","JPN":"こうしてる暇があるなら箱舟に行って中の奴らを\\n喰っちまった方がいいんじゃねえのか？","ENG":"We should just go to the Ark and devour everyone there instead.","TWN":"有這個時間，還不如去吃掉方舟裡的那些傢伙。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"닥쳐! 불만 있으면 네가 직접 전대장에게 따지던가!","JPN":"うるせえ！　文句があるならお前が直接戦隊長に言えばいいだろ！","ENG":"Shut up! You can take it up to the Commander yourself, if you don't like it!","TWN":"閉嘴！你要是有什麼不滿，就自己去問隊長！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"왜, 난 만만하고 전대장 손에 뒈지는 건 무섭나?","JPN":"どうした？　俺には文句が言えて戦隊長に殺されるのは怖いのか？","ENG":"What, are you too chicken to deal with the Commander but not me?","TWN":"怎麼，你看我好說話，敢對我說，卻不敢對隊長講嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SHIELD_ADMIN_CORRUPT_MAZE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"어차피 너나 나나 죽으면 그 녀석들 한 끼 식사거리밖에 안 돼.","JPN":"どうせ俺も貴様も、死んでしまえばあいつらの食事代わりだ。","ENG":"Don't forget we're nothing but lunch meat to them if we die.","TWN":"不管是你還是我，死了就只是成為他們的一餐而已。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"그러니 닥치고 무기 들어!","JPN":"わかったら武器を持ちやがれ！","ENG":"So grab your weapon and shut up!","TWN":"所以給我閉上嘴巴，拿起你的武器！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"큭......?! 매복인가?!","JPN":"くっ……！？　待ち伏せか！？","ENG":"Ugh! An ambush?","TWN":"唔……？！是埋伏嗎？！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_04"},{"id":"L33_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"좋아! 완벽하게 포위했다! 되는 대로 쏴 갈겨!","JPN":"よし！　完璧に包囲した！　撃て撃て撃ちまくれェーッ！","ENG":"Great! We have her surrounded! Light her up!","TWN":"很好！完全包圍了！把所有能射的東西都射出去！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"네놈 시체를 걸어 놓고 파티를 열어 주마! 바퀴벌레!","JPN":"貴様の死体を掲げてパーティーを開いてやるぜ！　ゴキブリ！","ENG":"We'll use your dead body as a pinata for our next party! You cursed Roach!","TWN":"我會把你的屍體掛起來開派對的！蟑螂！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내 부대원의 목소리로......!","JPN":"我が部隊員の姿と声で……！","ENG":"Don't you dare use my troops' voice...","TWN":"不准用我隊員的聲音……！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그 따위 소릴 지껄이지 마라!!","JPN":"そんな戯言を抜かすな！！","ENG":"To utter such idiocy!","TWN":"說這種鬼話！！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};